'use client' // Error boundaries 必須是 Client Component
import { useEffect } from 'react'

export default function Error({
  error,
  reset,
}: {
  error: Error & { digest?: string }
  reset: () => void
}) {
  useEffect(() => {
    // 上報錯誤；production 只有 digest，用它對應 server log
    reportError(error)
  }, [error])
  return (
    <div>
      <h2>發生錯誤</h2>
      <button onClick={() => reset()}>重試</button>
    </div>
  )
}

