// 四層快取對照表（觀念用，非可執行程式）
// | 機制                 | 存什麼             | 在哪裡  | 活多久                          |
// | Request Memoization | 函式回傳值          | Server | 單次 request 的 render pass     |
// | Data Cache          | 資料 (fetch 結果)  | Server | 持久（可 revalidate、跨部署保留） |
// | Full Route Cache    | HTML + RSC Payload | Server | 持久（重新部署清空）             |
// | Router Cache        | RSC Payload        | Client | session + 時間 (staleTimes)     |

// app/products/[id]/page.tsx
// async Server Component 直接 fetch + 用 React cache 為非 fetch 來源去重
import { cache } from 'react'
import { db } from '@/lib/db'

// 非 fetch 來源（DB）用 React cache 做單次渲染去重
export const getProduct = cache(async (id: string) => {
  return db.product.findUnique({ where: { id } })
})

export default async function Page({
  params,
}: {
  params: Promise<{ id: string }> // params 是 Promise，要 await
}) {
  const { id } = await params

  // 直接在 Server Component await
  const product = await getProduct(id)
  const reviews = await fetch(`https://api.example.com/reviews/${id}`, {
    cache: 'force-cache', // 明確 opt-in 才會進 Data Cache
  }).then((r) => r.json())

  return (
    <main>
      <h1>{product?.name}</h1>
      <ReviewList reviews={reviews} />
    </main>
  )
}

