// 回報所有 server 端錯誤到觀測平台
export const onRequestError: Instrumentation.onRequestError = async (
  err,
  request,
  context
) => {
  await fetch('https://.../report-error', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      message: err.message,
      digest: (err as { digest?: string }).digest,
      path: request.path,           // e.g. /blog?name=foo
      method: request.method,       // GET / POST ...
      routerKind: context.routerKind,
      routeType: context.routeType, // render | route | action | proxy
    }),
  })
}

import { after } from 'next/server'
import { cookies, headers } from 'next/headers'
import { logUserAction } from '@/app/utils'

// Route Handler / Server Action：可在 after callback 內直接讀 request API
export async function POST(request: Request) {
  // ...主要 mutation
  after(async () => {
    const userAgent = (await headers()).get('user-agent') || 'unknown'
    const session = (await cookies()).get('session-id')?.value || 'anonymous'
    logUserAction({ session, userAgent })
  })
  return Response.json({ status: 'success' })
}

// Server Component：不能在 after 內呼叫 cookies()/headers()
// 必須在 render 期先讀好，再用 closure 傳進去
export default async function Page() {
  const userAgent = (await headers()).get('user-agent') || 'unknown'
  after(() => {
    logUserAction({ userAgent }) // 用先讀好的值
  })
  return <h1>My Page</h1>
}

