// app/actions.ts
'use server'

import { z } from 'zod'
import { auth } from '@/lib/auth'
import { db } from '@/lib/db'

const schema = z.object({ postId: z.string().uuid() })

export async function deletePostAction(input: unknown) {
  // 1) 驗證參數（runtime 不能信 TS 型別）
  const { postId } = schema.parse(input)

  // 2) authentication：action 內自己驗，不靠 page 層
  const session = await auth()
  if (!session?.user) throw new Error('Unauthorized')

  // 3) authorization：檢查擁有權，避免 IDOR
  const post = await db.post.findUnique({ where: { id: postId } })
  if (!post || post.authorId !== session.user.id) {
    throw new Error('Forbidden')
  }

  await db.post.delete({ where: { id: postId } })
  // 4) 只回 UI 需要的，不回整筆 record
  return { success: true }
}

